// Main javascript entry point
// Should handle bootstrapping/starting application

'use strict';

import $ from 'jquery';
import TweenMax from 'gsap';
import 'gsap/src/uncompressed/plugins/ScrollToPlugin';
import ScrollMagic from 'scrollmagic';
import 'scrollmagic/scrollmagic/uncompressed/plugins/animation.gsap';
import 'scrollmagic/scrollmagic/uncompressed/plugins/debug.addIndicators';

$(() => {

  // Mobile Nav
  var toggle = $('.page-nav-toggle');
  var pageNav = $('#page-nav');

  toggle.click(function() {
    $(this).toggleClass('active');
    pageNav.toggleClass('open');
  });

  $('.page-nav__link').click(function() {
    toggle.toggleClass('active');
    pageNav.toggleClass('open');
  });

  // Init ScrollMagic
  var controller = new ScrollMagic.Controller();

  // Intro Tween
  var introtween = TweenMax.to('.section__top', 0.2, {
    transform: 'translate3d(0,15vh, 0)'
  });

  // Intro Scroll
  var intro = new ScrollMagic.Scene({
    triggerElement: '#intro',
    triggerHook: 0,
    duration: '50%'
  })
  .setTween(introtween)
  .addTo(controller);

  // About Scroll
  var about = new ScrollMagic.Scene({
    triggerElement: '#about',
    offset: -100
  })
  .setClassToggle('#content', 'about-active')
  .addTo(controller);

  // Project Scroll
  $('.project').each(function() {

    new ScrollMagic.Scene({
      triggerElement: this,
      reverse: false
    })
    .setClassToggle(this, 'project--active')
    .addTo(controller);
  });

  /*
  scene_object = {
    '[scene-name]' : {
      '[target-scene-id]' : '[anchor-href-value]'
    }
  }
  */
  var scenes = {
    'intro': {
      'about': 'aboutAnchor'
    },
    'scene2': {
      'skills': 'skillsAnchor'
    },
    'scene3': {
      'work': 'workAnchor'
    }
  };


  for(var key in scenes) {
    // skip loop if the property is from prototype
    if (!scenes.hasOwnProperty(key)) continue;

    var obj = scenes[key];

    for (var prop in obj) {
      // skip loop if the property is from prototype
      if(!obj.hasOwnProperty(prop)) continue;

      new ScrollMagic.Scene({
        triggerElement: '#'+prop,
        duration: $('#'+prop).height()+50,
        triggerHook: .1,
        reverse: true
      })
      .setClassToggle('#'+obj[prop], 'active')
      .addTo(controller);
    }
  }

  // Change behaviour of controller
  // to animate scroll instead of jump
  controller.scrollTo(function(target) {

    TweenMax.to(window, 0.5, {
      scrollTo : {
        y : target-80,
        autoKill : true // Allow scroll position to change outside itself
      },
      ease : Cubic.easeInOut
    });

  });

  // Bind scroll to anchor links using jQuery
  pageNav.on('click', 'a[href^="#"]', function(e) {
    var id = $(this).attr('href');

    if($(id).length > 0) {
      e.preventDefault();

      // trigger scroll
      controller.scrollTo(id);

      // If supported by the browser we can also update the URL
      if (window.history && window.history.pushState) {
        history.pushState('', document.title, id);
      }
    }

  });

  console.log("%c Thanks for checking out my code. I'm sure you're wondering, and the answer is yes, I did build this site myself. :)", 'background: #22FFD2; color: #001772; display: block;');

});
